"""Pinned-current-bytes tripwire for the V3Complete delegation signing pre-image.

CROSS-SDK PROVISIONAL TRIPWIRE (rs#1795 OPEN). kailash-rs LEADS and authored
these hex vectors from its own ``delegation_signing_payload``
(``workspaces/issue-1720-llm-consolidation/wave-b-ref/``
``multisig_v3_signing_pinned_vectors.rs``). They are the canonical JCS
pre-image bytes BOTH SDKs MUST reproduce byte-for-byte. The vectors are
PROVISIONAL until the cross-SDK re-pin lands (``cross-sdk-inspection.md``
Rule 4b): if kailash-rs re-pins them, they MUST be re-pinned here in the SAME
lockstep event, never edited incidentally.

Fixed inputs (only the multi-sig policy varies across vectors) mirror the rs
``fixed_inputs()`` / ``key(n) = [n; 32]``:

* ``delegation_id`` = ``00000000-0000-4000-8000-000000000001``
* ``delegator`` = ``alice``, ``delegate`` = ``bob``
* ``capabilities`` = ``["LlmCall"]``
* ``created_at`` = ``2026-01-02T03:04:05+00:00`` (RFC3339 +00:00, NOT Z)
* ``constraints`` / ``resource_limits`` = ``for_level(TrustLevel.SUPERVISED)``
* ``scope`` = ``DelegationScope.new("engineering").with_operation("read")``
"""

from __future__ import annotations

from datetime import datetime, timezone

import pytest

from kailash.trust.signing.delegation_payload import (
    ConstraintDimensions,
    DelegationScope,
    DelegationSigningInput,
    MultiSigSigningPolicy,
    ResourceLimits,
    SigningPayloadVersion,
    TrustLevel,
    delegation_signing_payload,
)

pytestmark = pytest.mark.regression

# --- Pinned canonical pre-image bytes (lowercase hex) ------------------------
# GENERATED BY kailash-rs; re-pin only in a cross-SDK lockstep event (rs#1795).

V1_2_OF_3 = ""

V2_1_OF_1 = ""

V3_3_OF_5 = ""

S2_ZERO_ONE = ""

S3_ONE_BYTE_DIFF = ""

# Byte-neutrality anchor: the SAME fixed record signed NON-multi-sig
# (V2Complete). NO ``multi_sig*`` key; version token ``"v2-complete"``.
V2C_NON_MULTI_SIG = ""


def _key(n: int) -> bytes:
    """Mirror the rs ``key(n) = [n; 32]`` fixed-input helper."""
    return bytes([n]) * 32


def _fixed_input(
    *,
    multi_sig: bool,
    policy: MultiSigSigningPolicy | None,
) -> DelegationSigningInput:
    """Mirror the rs ``fixed_inputs()`` — only the multi-sig policy varies."""
    return DelegationSigningInput(
        delegation_id="00000000-0000-4000-8000-000000000001",
        delegator="alice",
        delegate="bob",
        capabilities=("LlmCall",),
        created_at=datetime(2026, 1, 2, 3, 4, 5, tzinfo=timezone.utc),
        constraints=ConstraintDimensions.for_level(TrustLevel.SUPERVISED),
        resource_limits=ResourceLimits.for_level(TrustLevel.SUPERVISED),
        scope=DelegationScope.new("engineering").with_operation("read"),
        expires_at=None,
        parent_delegation_id=None,
        multi_sig=multi_sig,
        multi_sig_policy=policy,
        reasoning_trace_hash=None,
    )


def _v3_hex(policy: MultiSigSigningPolicy) -> str:
    payload = delegation_signing_payload(
        _fixed_input(multi_sig=True, policy=policy),
        SigningPayloadVersion.V3_COMPLETE,
    )
    return payload.hex()


def test_v3_multi_sig_preimage_reproduces_pinned_vectors() -> None:
    """V1/V2/V3/S2/S3 reproduce the kailash-rs pinned V3Complete bytes exactly."""
    v1 = MultiSigSigningPolicy.new(2, [_key(1), _key(2), _key(3)])
    v2 = MultiSigSigningPolicy.new(1, [_key(9)])
    v3 = MultiSigSigningPolicy.new(3, [_key(5), _key(4), _key(3), _key(2), _key(1)])
    s2 = MultiSigSigningPolicy.new(1, [_key(0), _key(1)])
    last = bytearray(32)
    last[31] = 1
    s3 = MultiSigSigningPolicy.new(2, [_key(0), bytes(last)])

    assert _v3_hex(v1) == V1_2_OF_3, "V1 (2-of-3) pin drifted"
    assert _v3_hex(v2) == V2_1_OF_1, "V2 (1-of-1) pin drifted"
    assert _v3_hex(v3) == V3_3_OF_5, "V3 (3-of-5) pin drifted"
    assert _v3_hex(s2) == S2_ZERO_ONE, "S2 (zero/one keys) pin drifted"
    assert _v3_hex(s3) == S3_ONE_BYTE_DIFF, "S3 (1-byte-diff) pin drifted"


def test_v3_authorized_signers_are_canonically_ordered() -> None:
    """S1: a reverse-insertion signer SET equal to V1's reproduces V1's bytes.

    The fold sorts the hex signer keys, so the pre-image binds the SET +
    threshold, not the stored insertion order.
    """
    reversed_policy = MultiSigSigningPolicy.new(2, [_key(3), _key(2), _key(1)])
    assert (
        _v3_hex(reversed_policy) == V1_2_OF_3
    ), "reverse-order signer set MUST fold to the same canonical bytes as V1"


def test_v3_single_byte_signer_change_changes_the_bytes() -> None:
    """S2 and S3 differ only in the last byte of the second signer.

    The pre-image MUST differ — the signer set is genuinely signature-bound.
    """
    assert (
        S2_ZERO_ONE != S3_ONE_BYTE_DIFF
    ), "a one-byte signer change MUST change the pre-image"
    s2 = MultiSigSigningPolicy.new(1, [_key(0), _key(1)])
    last = bytearray(32)
    last[31] = 1
    s3 = MultiSigSigningPolicy.new(2, [_key(0), bytes(last)])
    assert _v3_hex(s2) != _v3_hex(s3)


def test_non_multi_sig_v2_bytes_are_byte_neutral() -> None:
    """V2C: the SAME fixed record signed NON-multi-sig (V2Complete) is unchanged.

    rs#1795 invariant: the V3 fold is byte-CHANGING for MULTI-SIG records ONLY.
    """
    payload = delegation_signing_payload(
        _fixed_input(multi_sig=False, policy=None),
        SigningPayloadVersion.V2_COMPLETE,
    )
    hexed = payload.hex()
    assert hexed == V2C_NON_MULTI_SIG, "non-multi-sig V2 bytes drifted"

    text = payload.decode("utf-8")
    assert "multi_sig" not in text, "non-multi-sig record leaked a multi_sig key"
    assert "v3-complete" not in text, "non-multi-sig record carries the v3 token"
    assert "v2-complete" in text, "non-multi-sig record MUST be v2-complete"


def test_v3_bytes_carry_the_folded_policy_and_v3_token() -> None:
    """Positive structural check: folded keys + self-describing token present."""
    v1 = MultiSigSigningPolicy.new(2, [_key(1), _key(2), _key(3)])
    payload = delegation_signing_payload(
        _fixed_input(multi_sig=True, policy=v1),
        SigningPayloadVersion.V3_COMPLETE,
    )
    text = payload.decode("utf-8")
    assert '"multi_sig_threshold":2' in text
    assert '"multi_sig_authorized_signers":[' in text
    assert '"signing_payload_version":"v3-complete"' in text
    # The bundle is NOT folded into the pre-image.
    assert "multi_sig_bundle" not in text


def test_pre_image_is_ascii_only() -> None:
    """§5.3 pre-image is ASCII-only by construction (delegate-encoder byte parity)."""
    v1 = MultiSigSigningPolicy.new(2, [_key(1), _key(2), _key(3)])
    payload = delegation_signing_payload(
        _fixed_input(multi_sig=True, policy=v1),
        SigningPayloadVersion.V3_COMPLETE,
    )
    assert payload.decode("ascii")  # raises if any non-ASCII byte present
